export type SubjectKey = "russian" | "math" | "social";
export type QuestionMode = "diagnosis" | "session" | "both";

export type RussianTaskType =
  | "пунктуация"
  | "лексика"
  | "текст"
  | "грамматика"
  | "орфоэпия"
  | "орфография";

export type MathTaskType =
  | "уравнения"
  | "функции"
  | "геометрия"
  | "вероятность"
  | "текстовая_задача"
  | "вычисления"
  | "прогрессия"
  | "производная";

export type SocialTaskType =
  | "экономика"
  | "право"
  | "политика"
  | "социология"
  | "человек_и_общество"
  | "духовная_сфера";

export type TaskType = RussianTaskType | MathTaskType | SocialTaskType;

export type BankQuestion = {
  id: string;
  subject: SubjectKey;
  mode: QuestionMode;
  taskType: TaskType;
  examLabel?: "Формат ЕГЭ" | "Типовое задание" | "По структуре экзамена";
  skillLabel?: string;
  rule?: string;
  solutionSteps?: string;
  commonMistake?: string;
  repeatHint?: string;
  topic: string;
  difficulty: "easy" | "medium" | "hard";
  prompt: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
};


export type TaskTypeGuide = { taskType: TaskType; title: string; rule: string; example: string; trap: string; };

