export function getTaskTypeGuide(taskType?: TaskType | null) {
  return taskType ? TASK_TYPE_GUIDES[taskType] ?? null : null;
}

export type MiniVariant = {
  id: string;
  subject: SubjectKey;
  variantNumber: number;
  questions: BankQuestion[];
};

type QuestionInput = Omit<BankQuestion, "id" | "subject" | "mode" | "taskType">;

function inferRussianTaskType(topic: string): RussianTaskType {
  if (topic === "Пунктуация" || topic === "Сложное предложение") return "пунктуация";
  if (topic === "Лексика" || topic === "Паронимы" || topic === "Средства выразительности") return "лексика";
  if (topic === "Текст") return "текст";
  if (topic === "Орфоэпия" || topic === "Ударение") return "орфоэпия";
  if (topic === "Орфография") return "орфография";
  return "грамматика";
}

function inferMathTaskType(topic: string): MathTaskType {
  if (topic === "Функции" || topic === "Графики" || topic === "Тригонометрия") return "функции";
  if (topic === "Геометрия" || topic === "Планиметрия" || topic === "Стереометрия") return "геометрия";
  if (topic === "Вероятность") return "вероятность";
  if (topic === "Текстовые задачи") return "текстовая_задача";
  if (topic === "Последовательности" || topic === "Прогрессии") return "прогрессия";
  if (topic === "Производная") return "производная";
  if (topic === "Уравнения" || topic === "Неравенства") return "уравнения";
  return "вычисления";
}

function inferSocialTaskType(topic: string): SocialTaskType {
  if (topic === "Экономика") return "экономика";
  if (topic === "Право") return "право";
  if (topic === "Политика") return "политика";
  if (topic === "Социология" || topic === "Социальные отношения") return "социология";
  if (topic === "Человек и общество") return "человек_и_общество";
  return "духовная_сфера";
}

function inferTaskType(subject: SubjectKey, topic: string): TaskType {
  if (subject === "math") return inferMathTaskType(topic);
  if (subject === "social") return inferSocialTaskType(topic);
  return inferRussianTaskType(topic);
}


function formatSkillLabel(taskType: TaskType, topic: string) {
  const fromTask = taskType.replaceAll("_", " ");
  if (fromTask.length > 0) return fromTask.charAt(0).toUpperCase() + fromTask.slice(1);
  return topic;
}

function inferExamLabel(mode: QuestionMode, index: number): BankQuestion["examLabel"] {
  if (mode === "diagnosis") return "По структуре экзамена";
  return index % 3 === 0 ? "Формат ЕГЭ" : "Типовое задание";
}

function buildDefaultSolutionSteps(subject: SubjectKey, taskType: TaskType, topic: string) {
  if (subject === "math") return "Выпиши данные из условия, выбери формулу или преобразование, затем проверь вычисление и ответ.";
  if (subject === "social") return "Выдели ключевой термин в ситуации, сравни признаки вариантов и выбери тот, который точно подходит по смыслу.";
  if (taskType === "пунктуация") return "Найди грамматические основы, определи конструкцию и только затем ставь знак по правилу.";
  if (taskType === "орфография") return "Определи часть слова и орфограмму, вспомни правило или исключение, затем выбирай букву.";
  return "Определи, какой навык проверяется, вспомни правило и проверь каждый вариант по смыслу.";
}

function buildDefaultRepeatHint(taskType: TaskType, skillLabel: string) {
  const guide = getTaskTypeGuide(taskType);
  return guide ? `${guide.title}: повтори правило, пример и типичную ловушку перед следующей тренировкой.` : `${skillLabel}: повтори правило и реши похожее задание.`;
}

function createQuestions(subject: SubjectKey, mode: QuestionMode, entries: QuestionInput[]) {
  return entries.map((entry, index) => {
    const taskType = inferTaskType(subject, entry.topic);

    return {
      id: `${subject}-${mode}-${index + 1}`,
      subject,
      mode,
      taskType,
      examLabel: entry.examLabel ?? inferExamLabel(mode, index),
      skillLabel: entry.skillLabel ?? formatSkillLabel(taskType, entry.topic),
      rule: entry.rule ?? getTaskTypeGuide(taskType)?.rule,
      solutionSteps: entry.solutionSteps ?? buildDefaultSolutionSteps(subject, taskType, entry.topic),
      commonMistake: entry.commonMistake ?? getTaskTypeGuide(taskType)?.trap,
      repeatHint: entry.repeatHint ?? buildDefaultRepeatHint(taskType, entry.skillLabel ?? formatSkillLabel(taskType, entry.topic)),
      ...entry,
    };
  });
}

function shuffle<T>(items: T[]) {
  const copy = [...items];

  for (let index = copy.length - 1; index > 0; index -= 1) {
    const randomIndex = Math.floor(Math.random() * (index + 1));
    [copy[index], copy[randomIndex]] = [copy[randomIndex], copy[index]];
  }

  return copy;
}

